#include <iostream>
#include <string>

enum Day
{
    Sunday, Monday, Tuesday, Wednesday, Thursday, Friday, Saturday
};

Day parseDay(const std::string& name)
{
    if (name == "Sunday")    return Sunday;
    if (name == "Monday")    return Monday;
    if (name == "Tuesday")   return Tuesday;
    if (name == "Wednesday") return Wednesday;
    if (name == "Thursday")  return Thursday;
    if (name == "Friday")    return Friday;
    return Saturday;
}

int main()
{
    std::string startName{};
    std::string targetName{};
    std::cin >> startName >> targetName;

    Day start{ parseDay(startName) };
    Day target{ parseDay(targetName) };

    int diff{ ((target - start) % 7 + 7) % 7 };

    std::cout << diff << '\n';

    return 0;
}
